mapper.select:
WITH committees AS ( SELECT c.doc_type, TO_CHAR(TO_DATE(c.comm_dt, 'YYYYMMDD'), 'YYYY-MM') AS comm_yyyymm, TO_CHAR(TO_DATE(c.comm_dt, 'YYYYMMDD'), 'YYYY-MM-DD') AS comm_date, COUNT(*) AS count FROM esg.tb_committee c /* 특정 인원에 대한 위원회 조회시 주석 해제 */ -- JOIN esg.tb_approval_info ai -- ON ai.target_id = CONCAT(c.write_year, c.doc_no) -- AND ai.target_type = c.doc_type -- AND ai.hr_id = '202410080050' -- :hr_id WHERE c.comp_id = #{compId} -- :comp_id /* 특정 위워횐 조회시 주석 해제 */ -- AND c.doc_type IN ('OHC', 'PAC') -- :category
AND c.comm_dt BETWEEN #{startDate} AND #{endDate}
AND c.use_yn = 'Y' GROUP BY c.doc_type, TO_CHAR(TO_DATE(c.comm_dt, 'YYYYMMDD'), 'YYYY-MM'), TO_CHAR(TO_DATE(c.comm_dt, 'YYYYMMDD'), 'YYYY-MM-DD') ), formatted_committees AS ( SELECT doc_type, comm_yyyymm, JSON_OBJECT_AGG(comm_date, count ORDER BY comm_date) AS dates_counts FROM committees GROUP BY doc_type, comm_yyyymm ORDER BY doc_type, comm_yyyymm ) SELECT doc_type, JSON_AGG(dates_counts) AS dates_array FROM formatted_committees GROUP BY doc_type
